import React from 'react';
// This line links App.js to your Menu.js file
import Menu from './Menu'; 

function App() {
  return (
    <div style={{ 
      backgroundColor: '#000', 
      minHeight: '100vh', 
      color: '#fff', 
      fontFamily: 'Arial, sans-serif' 
    }}>
      {/* Header Section */}
      <header style={{ 
        padding: '60px 20px', 
        textAlign: 'center', 
        borderBottom: '1px solid #222' 
      }}>
        <h1 style={{ 
          color: '#D4AF37', 
          fontSize: '3.5rem', 
          margin: 0, 
          letterSpacing: '8px',
          textTransform: 'uppercase' 
        }}>
          ÀMÍ BY T
        </h1>
        <p style={{ 
          color: '#E07A5F', 
          letterSpacing: '4px', 
          marginTop: '10px',
          textTransform: 'uppercase',
          fontSize: '0.9rem'
        }}>
          Taste and Style
        </p>
      </header>

      {/* Main Content - This pulls in your Small Chops menu */}
      <main>
        <Menu />
      </main>

      {/* Footer Section */}
      <footer style={{ 
        textAlign: 'center', 
        padding: '40px 20px', 
        color: '#444',
        fontSize: '0.8rem',
        letterSpacing: '2px'
      }}>
        <p>© 2026 ÀMÍ BY T | LAGOS, NIGERIA</p>
      </footer>
    </div>
  );
}

export default App;
